#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, x[105], y[105];
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> x[i] >> y[i];
    }
    int S = 0;
    for (int i = 1; i <= n - 1; i++) {
        S += (x[i] * y[i + 1] - x[i + 1] * y[i]) + (x[n] * y[1] - x[1] * y[n]);
    }
    S = abs(S) / 2;
    cout << S;
    return 0;
}
